using System.Text.RegularExpressions;
using GutAI.Application.Common.DTOs;

namespace GutAI.Infrastructure.Services;

internal static class FodmapData
{
    // Record types for the data entries
    internal record IngredientEntry(string Pattern, Regex? Regex, FodmapTriggerDto Trigger);
    internal record WholeFoodEntry(string Pattern, FodmapTriggerDto Trigger);
    internal record AdditiveNameEntry(string Pattern, FodmapTriggerDto Trigger);

    internal static readonly IReadOnlyList<IngredientEntry> IngredientTriggers;
    internal static readonly IReadOnlyList<WholeFoodEntry> WholeFoodTriggers;
    internal static readonly IReadOnlyDictionary<string, FodmapTriggerDto> Additives;
    internal static readonly IReadOnlyList<AdditiveNameEntry> AdditiveNameTriggers;
    internal static readonly IReadOnlySet<string> GenericWholeFoodPatterns;

    static FodmapData()
